import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface TrafficSource {
  name: string;
  value: number;
}

interface AnalyticsData {
  currentStats: {
    visitors: number;
    pageViews: number;
    bounceRate: number;
  };
  trafficSources: TrafficSource[];
}

export default function Widget() {
  const analyticsData = response.data as AnalyticsData;
  const { currentStats, trafficSources } = analyticsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: 'rgba(0, 0, 0, 0.6)', backdropFilter: 'blur(10px)', borderRadius: 3, color: '#F8FAFC' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#3B82F6' }}>
              Website Analytics
            </Typography>
            <Stack direction="row" justifyContent="space-between" sx={{ mt: 1 }}>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Visitors
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {currentStats.visitors}
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Page Views
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {currentStats.pageViews}
                </Typography>
              </Box>
              <Box>
                <Typography variant="caption" color="text.secondary">
                  Bounce Rate
                </Typography>
                <Typography variant="body2" fontWeight={500}>
                  {currentStats.bounceRate}%
                </Typography>
              </Box>
            </Stack>
          </Box>

          <PieChart
            height={150}
            series={[
              {
                data: trafficSources.map(source => ({
                  id: source.name,
                  value: source.value,
                })),
                colorScheme: ['#3B82F6', '#EF4444', '#F59E0B', '#10B981'],
              },
            ]}
            sx={{
              '& .MuiPieElement-root': {
                strokeWidth: 0,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
